snippets.C0016:
// Express (Node Web Framework) · 5.0.0
// Ubicación sugerida: ver comentarios.
// Node.js · Caso: Top-K frecuentes | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr, k) {
  const freq = new Map();
  for (const x of arr) freq.set(x, (freq.get(x) || 0) + 1);
  return [...freq.entries()].sort((a,b)=>b[1]-a[1]).slice(0,k).map(([v])=>v);
}

snippets.C0017:
// Express (Node Web Framework) · 5.0.0
// Ubicación sugerida: ver comentarios.
// Node.js · Caso: Two Sum | Nivel: Intermedio | Categoría: Map/Hash

function solve(arr, target) {
  const seen = new Map();
  for (let i=0;i<arr.length;i++) {
    const need = target - arr[i];
    if (seen.has(need)) return [seen.get(need), i];
    seen.set(arr[i], i);
  }
  return null;
}

