// Express (Node Web Framework) · 5.0.0
// Ubicación sugerida: ver comentarios.
// Node.js · Caso: Búsqueda binaria | Nivel: Intermedio | Categoría: Búsqueda

function solve(arr, target) {
  let lo=0, hi=arr.length-1;
  while (lo<=hi) {
    const mid = Math.floor((lo+hi)/2);
    if (arr[mid]===target) return mid;
    if (arr[mid]<target) lo=mid+1; else hi=mid-1;
  }
  return -1;
}

