// Express (Node Web Framework) · 5.0.0
// Ubicación sugerida: ver comentarios.
// C0666 · Merge sort (Intermedio, Algoritmos)
function solve(arr){
  if(arr.length<=1) return arr;
  const mid = Math.floor(arr.length/2);
  const left = solve(arr.slice(0,mid));
  const right= solve(arr.slice(mid));
  const out=[];
  let i=0,j=0;
  while(i<left.length && j<right.length){
    if(left[i]<=right[j]) out.push(left[i++]);
    else out.push(right[j++]);
  }
  return out.concat(left.slice(i)).concat(right.slice(j));
}

