// Express (Node Web Framework) · 5.0.0
// Ubicación sugerida: ver comentarios.
// C0669 · LRU cache (Intermedio, Algoritmos)
// LRU con Map (inserción ordenada). O(1) promedio.
class LRU {
  constructor(cap){ this.cap=cap; this.map=new Map(); }
  get(k){
    if(!this.map.has(k)) return null;
    const v = this.map.get(k);
    this.map.delete(k);
    this.map.set(k,v);
    return v;
  }
  put(k,v){
    if(this.map.has(k)) this.map.delete(k);
    this.map.set(k,v);
    if(this.map.size>this.cap){
      const oldest = this.map.keys().next().value;
      this.map.delete(oldest);
    }
  }
}

