// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import express from "express";
const app = express();
app.use(express.json());

const items = new Map();
let seq = 1;

app.get("/items", (_req,res)=>res.json([...items.values()]));
app.post("/items", (req,res)=>{
  const it = { id: seq++, name: String(req.body.name||"") };
  items.set(it.id, it);
  res.status(201).json(it);
});
app.put("/items/:id", (req,res)=>{
  const id = Number(req.params.id);
  if(!items.has(id)) return res.status(404).json({ error:"not_found" });
  const it = { id, name: String(req.body.name||"") };
  items.set(id, it);
  res.json(it);
});
app.delete("/items/:id", (req,res)=>{
  items.delete(Number(req.params.id));
  res.status(204).end();
});

