// C0688 · Auth por sesión (login/logout)
import express from "express";
import session from "express-session"; // npm i express-session
const app = express(); app.use(express.json());

app.use(session({
  secret: process.env.SESSION_SECRET || "dev-secret",
  resave: false,
  saveUninitialized: false,
  cookie: { httpOnly: true }
}));

app.post("/login", (req,res)=>{ req.session.user = { id:"user-1" }; res.json({ ok:true }); });
app.post("/logout", (req,res)=>req.session.destroy(()=>res.json({ ok:true })));

function requireAuth(req,res,next){
  if(!req.session.user) return res.status(401).json({ error:"unauthorized" });
  next();
}
app.get("/me", requireAuth, (req,res)=>res.json(req.session.user));

