// WebSocket con 'ws'
// npm i ws
import http from "node:http";
import { WebSocketServer } from "ws";

const server = http.createServer();
const wss = new WebSocketServer({ server });

wss.on("connection", (ws)=>{
  ws.on("message", (msg)=>{
    const s = msg.toString();
    ws.send(s === "ping" ? "pong" : s);
  });
});

server.listen(3000);

